import{_ as a,o,c as t,a2 as n}from"./chunks/framework.CKCxdkvf.js";const u=JSON.parse('{"title":"ADR-042 — ISS Explorer low-end fallback (?view=list + heuristics)","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-042.md","filePath":"adr/ADR-042.md"}'),r={name:"adr/ADR-042.md"};function i(s,e,l,d,c,h){return o(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="adr-042-—-iss-explorer-low-end-fallback-view-list-heuristics" tabindex="-1">ADR-042 — ISS Explorer low-end fallback (<code>?view=list</code> + heuristics) <a class="header-anchor" href="#adr-042-—-iss-explorer-low-end-fallback-view-list-heuristics" aria-label="Permalink to &quot;ADR-042 — ISS Explorer low-end fallback (`?view=list` + heuristics)&quot;">​</a></h1><blockquote><p>Status · Accepted<br> Date · 2026-05-05<br> Closes · RFC-013 (with ADR-040, ADR-041)<br> TA anchor · §components<br> Related · ADR-025 (accessibility), PRD-010</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>RFC-013 OQ-3 requires a non-WebGL path and automatic degradation on weak devices.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><h3 id="url-override" tabindex="-1">URL override <a class="header-anchor" href="#url-override" aria-label="Permalink to &quot;URL override&quot;">​</a></h3><p><strong><code>?view=list</code></strong> forces <strong>list mode</strong>: alphabetical module list, same <code>src/lib/components/IssModulePanel.svelte</code> content. <strong>No WebGL</strong> initialisation — no <code>THREE.WebGLRenderer</code>, no GLB fetch.</p><h3 id="auto-fallback" tabindex="-1">Auto-fallback <a class="header-anchor" href="#auto-fallback" aria-label="Permalink to &quot;Auto-fallback&quot;">​</a></h3><p>After 3D mode starts, measure FPS for <strong>~2 s</strong> via <code>requestAnimationFrame</code> deltas. If <strong>sustained &lt; 20 fps</strong>, switch to list mode and <strong>dispose</strong> renderer, scene, and loader geometry.</p><p>If <strong><code>navigator.deviceMemory</code></strong> is defined and <strong><code>&amp;lt; 4</code></strong>, skip 3D and open in list mode immediately (Chrome/Android hint).</p><p>If <strong>WebGL context creation fails</strong>, list mode.</p><h3 id="ux" tabindex="-1">UX <a class="header-anchor" href="#ux" aria-label="Permalink to &quot;UX&quot;">​</a></h3><p>Single reactive <code>viewMode: &#39;3d&#39; | &#39;list&#39;</code> — avoid mounting canvas then unmounting in a way that flashes white; prefer deciding mode <strong>before</strong> first paint when URL/device hints demand list.</p><h3 id="toggle" tabindex="-1">Toggle <a class="header-anchor" href="#toggle" aria-label="Permalink to &quot;Toggle&quot;">​</a></h3><p>HUD control syncs URL (<code>view</code> search param) so shareable links reproduce mode.</p><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p><strong>Positive:</strong> Accessibility + low-end coverage without maintaining two full feature sets.</p><p><strong>Negative:</strong> <code>deviceMemory</code> is non-standard — treated as optional signal only.</p><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><p>FPS sampler runs only when <code>viewMode === &#39;3d&#39;</code> after GLB load completes.</p>',20)])])}const m=a(r,[["render",i]]);export{u as __pageData,m as default};
